  ('cpa-moex-00241', 'cpa', 'cpa-moex-112-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列何者不應列入查核報告中之查核意見段？', '["財務報表之名稱", "受查者", "財務報表之日期", "查核工作係依照一般公認審計準則執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "062554bc3cf7", "answer_pdf_sha1": "12b55ec2eaef", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00242', 'cpa', 'cpa-moex-112-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依審計準則規定，一般查核案件之工作底稿保管年限自何日起算？', '["受查核財務報表之資產負債表日", "查核報告日", "查核案件之工作底稿完成檔案彙整及歸檔日", "受查核財務報表經股東會承認日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "062554bc3cf7", "answer_pdf_sha1": "12b55ec2eaef", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00243', 'cpa', 'cpa-moex-112-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員為達成特定查核目的，就樣本執行適當之查核程序後，應評估抽樣結果，有關分析 樣本所查得之偏差或不實表達，下列相關敘述何者錯誤？', '["查核人員應決定是否確為偏差或不實表達", "某一樣本單位查核人員雖無法或未執行替代查核程序時，也不應將該樣本視為不實表達", "查核人員應考慮偏差或不實表達之性質、原因及其對其他相關查核工作之可能影響", "當查核目的為證實應收帳款之餘額時，應收帳款明細帳之過帳錯誤，不致影響應收帳款餘 額，不應視為不實表達"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "062554bc3cf7", "answer_pdf_sha1": "12b55ec2eaef", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00244', 'cpa', 'cpa-moex-112-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依據我國會計師職業道德規範公報，下列敘述何者錯誤？', '["會計師事務所內因職級不同，所受到的獨立性規範也會不同", "五年前曾擔任客戶之董監事者，不得擔任該客戶之查核團隊成員", "簽證會計師不得有與客戶一起共同投資事業之行為", "會計師不得為公開發行公司簽證客戶從事記帳工作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "062554bc3cf7", "answer_pdf_sha1": "12b55ec2eaef", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00245', 'cpa', 'cpa-moex-112-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員偵出導因於受查者未遵循法令事項之重大不實表達之能力，受財務報表查核僅能提', '["許多法令主要與受查者之業務經營 層面有關，該等法令通常對財務報表不具直接影響", "未遵循法令事項通常對財務報表影響 並不重大", "受查者可能故意隱瞞未遵循法令事項", "某項作為是否構成未遵循法令事項， 最終仍須由司法機關判定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "062554bc3cf7", "answer_pdf_sha1": "12b55ec2eaef", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00246', 'cpa', 'cpa-moex-112-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員於規劃及執行查核工作時，應適當應用重大性之觀念，下列相關敘述何者錯誤？', '["會計師認為有必要溝通與重大性之應用有關之事項時，可於查核報告中之強調事項段為之", "查核人員於查核過程中，發現實際財務績效與原用以決定財務報表整體重大性之預期財務 績效存有重大差異，則須修正該重大性", "財務報表之財務報導期間如長於或短於 12 個月（例如受查者係新成立或財務報導期間有 變更），重大性應根據該財務報導期間之財務報表決定", "會計師應於查核報告之會計師查核財務報表之責任段，敘明「如不實表達之個別金額或彙 總數可合理預期將影響財務報表使用者所作之經濟決策，則被認為具有重大性」等內容"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "062554bc3cf7", "answer_pdf_sha1": "12b55ec2eaef", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00247', 'cpa', 'cpa-moex-112-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列有關重大性之敘述何者錯誤？', '["如不實表達之個別金額或彙總數可合理預期將影響財務報表使用者之經濟決策，則被認為 具有重大性", "重大性受不實表達金額或性質之影響", "重大性設定的決定涉及專業判斷", "執行重大性為低於財務報表整體重大性之金額，其彙總數不得超過財務報表整體重大性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "062554bc3cf7", "answer_pdf_sha1": "12b55ec2eaef", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00248', 'cpa', 'cpa-moex-112-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列有關會計師採用查核人員專家工作之敘述，何者正確？', '["查核人員專家，係指查核人員聘僱或委任具有會計或審計領域專門知識之個人或組織", "查核人員應評估查核人員專家就查核目的而言是否具有所需之專業能力、適任能力及客觀性", "基於客觀性考量，查核人員所隸屬事務所或聯盟事務所之專業人員，不可受任為查核人員 專家", "會計師欲與查核人員專家區分查核責任，可於修正式意見查核報告之查核意見基礎段中提 及查核人員專家之工作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "062554bc3cf7", "answer_pdf_sha1": "12b55ec2eaef", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00249', 'cpa', 'cpa-moex-112-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '審計抽樣的進行順序為何？①分析偏差原因  ②挑取樣本  ③定義屬性及偏差情況  ④設定 查核測試之目標  ⑤設定可容忍偏差率', '["⑤", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "062554bc3cf7", "answer_pdf_sha1": "12b55ec2eaef", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00250', 'cpa', 'cpa-moex-112-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '國際財務報導準則（IFRS）及企業會計準則（EAS）係屬何種財務報導架構？', '["兩者皆為一般用途及允當表達架構", "兩者皆為一般用途及遵循架構", "IFRS為一般用途及允當表達架構，EAS則為一般用途及遵循架構", "IFRS為一般用途及允當表達架構，EAS則為特殊用途及遵循架構"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "062554bc3cf7", "answer_pdf_sha1": "12b55ec2eaef", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
